def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index."""
    # Check if index file exists
    if not Path(index_path).exists():
        raise FileNotFoundError(f"Index file not found: {index_path}")

    try:
        searcher = LeannSearcher(index_path)
        pm = searcher.passage_manager
        passages = pm.get_all_passages()
        total_passages = len(passages)

        metadata_fields = set()
        field_value_counts = defaultdict(Counter)

        for passage in passages:
            metadata = passage.metadata
            for field, value in metadata.items():
                metadata_fields.add(field)
                field_value_counts[field][value] += 1

        # Convert Counters to dictionaries for JSON serialization
        field_value_counts_dict = {
            field: dict(value_counter) 
            for field, value_counter in field_value_counts.items()
        }

        return {
            "total_passages": total_passages,
            "metadata_fields": sorted(list(metadata_fields)),
            "field_value_counts": field_value_counts_dict
        }
    except FileNotFoundError:
        raise FileNotFoundError(f"Index metadata file not found: {index_path}")

def analyze_index_coverage(
    index_path: str, 
    required_fields: List[str]
) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields."""
    # Check if index file exists
    if not Path(index_path).exists():
        raise FileNotFoundError(f"Index file not found: {index_path}")

    try:
        searcher = LeannSearcher(index_path)
        pm = searcher.passage_manager
        passages = pm.get_all_passages()
        total_passages = len(passages)

        # Count passages that have all required fields
        all_covered_count = 0
        field_presence = defaultdict(int)

        for passage in passages:
            metadata = passage.metadata
            has_all_required = True

            for field in required_fields:
                if field not in metadata:
                    has_all_required = False
                    break

            if has_all_required:
                all_covered_count += 1

            # Count presence of each required field
            for field in required_fields:
                if field in metadata:
                    field_presence[field] += 1

        # Calculate coverage percentages
        coverage_percentage = (
            (all_covered_count / total_passages * 100) 
            if total_passages > 0 
            else 0
        )

        field_coverage = {
            field: (count / total_passages * 100) 
            if total_passages > 0 
            else 0
            for field, count in field_presence.items()
        }

        # Identify missing fields (required fields not present in any passage)
        missing_fields = [
            field for field in required_fields 
            if field not in field_presence
        ]

        return {
            "coverage_percentage": round(coverage_percentage, 2),
            "field_coverage": {k: round(v, 2) for k, v in field_coverage.items()},
            "missing_fields": missing_fields
        }
    except FileNotFoundError:
        raise FileNotFoundError(f"Index metadata file not found: {index_path}")

