def export_index_metadata(index_path: str, output_file: str) -> Dict[str, Any]:
    """Export index metadata and passage information to a JSON file."""
    index_path_obj = Path(index_path)
    if not index_path_obj.exists():
        raise FileNotFoundError(f"Index metadata file not found: {index_path}")

    # Load the index
    builder = LeannBuilder()
    index = builder.load_index(index_path)
    passage_manager = index.passage_manager

    passages_data = []
    for passage in passage_manager.passages:
        passages_data.append({
            "id": passage.id,
            "text": passage.text,
            "vector": passage.vector.tolist()  # Convert numpy array to list
        })

    metadata = {
        "passages": passages_data,
        "index_metadata": index.metadata,
        "backend_name": index.backend_name,
        "dimensions": index.dimensions
    }

    with open(output_file, 'w') as f:
        json.dump(metadata, f, indent=2)

    return {
        "exported_passages": len(passages_data),
        "output_file": output_file,
        "status": "success"
    }

def import_index_from_metadata(export_file: str, index_path: str, backend_name: str = 'hnsw') -> Dict[str, Any]:
    """Import and rebuild an index from exported metadata and passages."""
    export_file_path = Path(export_file)
    if not export_file_path.exists():
        raise FileNotFoundError(f"Export file not found: {export_file}")

    try:
        with open(export_file, 'r') as f:
            data = json.load(f)
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON format in export file")

    # Validate structure
    required_fields = ["passages", "dimensions"]
    for field in required_fields:
        if field not in data:
            raise ValueError(f"Missing required field: {field}")

    passages = data["passages"]
    dimensions = data["dimensions"]

    if not isinstance(passages, list) or len(passages) == 0:
        raise ValueError("Invalid passages data")

    # Check each passage has required fields
    for i, passage in enumerate(passages):
        if not isinstance(passage, dict):
            raise ValueError(f"Passage at index {i} is not a dictionary")

        required_passage_fields = ["id", "text", "vector"]
        for field in required_passage_fields:
            if field not in passage:
                raise ValueError(f"Passage {i} missing field: {field}")

        if not isinstance(passage["vector"], list):
            raise ValueError(f"Passage {i} vector is not a list")

    # Initialize builder
    builder = LeannBuilder(backend_name=backend_name, dimensions=dimensions)

    # Add passages
    for passage in passages:
        builder.add_passage(
            text=passage["text"],
            passage_id=passage["id"],
            vector=passage["vector"]  # List of floats
        )

    # Build index
    builder.build_index(index_path)

    return {
        "index_path": index_path,
        "passages_imported": len(passages),
        "status": "success"
    }

