def search_with_result_expansion(
    index_path: str,
    query: str,
    expand_by_field: str,
    expansion_count: int = 1,
    top_k: int = 10
) -> List[SearchResult]:
    """Search in an index and expand results by including additional results with matching field values."""

    if expansion_count < 0:
        raise ValueError("expansion_count must be non-negative")

    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError:
        raise FileNotFoundError(f"Index file not found: {index_path}")

    initial_results = searcher.search(query, top_k=top_k)

    all_results = []
    seen_ids = set()

    # Add initial results
    for result in initial_results:
        if result.id not in seen_ids:
            all_results.append(result)
            seen_ids.add(result.id)

    # Expand results
    for result in initial_results:
        field_value = result.metadata.get(expand_by_field)
        if field_value is not None:
            # Handle special characters in field value
            if ' ' in str(field_value) or any(c in str(field_value) for c in ['\'', '"', '&', '|', '(', ')']):
                expansion_query = f"{expand_by_field}='{field_value}'"
            else:
                expansion_query = f"{expand_by_field}:{field_value}"

            try:
                expansion_results = searcher.search(expansion_query, top_k=expansion_count)
                for exp_result in expansion_results:
                    if exp_result.id not in seen_ids:
                        all_results.append(exp_result)
                        seen_ids.add(exp_result.id)
            except Exception:
                # Silently continue if expansion search fails
                pass

    return all_results

